// reviewerEscalatedEventBody renders the body for a reviewer-escalated event.
func reviewerEscalatedEventBody(newMinPower, reviewErrorCount int, resultRev string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "new_min_power=%d\n", newMinPower)
	fmt.Fprintf(&b, "review_error_count=%d\n", reviewErrorCount)
	if resultRev != "" {
		fmt.Fprintf(&b, "result_rev=%s\n", resultRev)
	}
	return b.String()
}

// countPriorEscalationTriggers counts review-error and review-pairing-degraded
// events recorded for the given bead whose body cites the given result_rev.
// Both event kinds signal that the reviewer should escalate MinPower on the
// next dispatch attempt for that result candidate.
func countPriorEscalationTriggers(store BeadEventReader, beadID, resultRev string) int {
	if store == nil || resultRev == "" {
		return 0
	}
	events, err := store.Events(beadID)
	if err != nil {
		return 0
	}
	n := 0
	for _, ev := range events {
		if ev.Kind != "review-error" && ev.Kind != ReviewPairingDegradedEventKind {
			continue
		}
		m := reResultRevField.FindStringSubmatch(ev.Body)
		if m == nil || m[1] != resultRev {
			continue
		}
		n++
	}
	return n
}

