func (r *DefaultBeadReviewer) reviewerProfileForDispatch(ctx context.Context, impl ImplementerRouting) string {
	return r.reviewerDispatchProfile(ctx, impl, 0).Name
}

// reviewerDispatchProfile computes the fizeau profile and MinPower floor for
// the reviewer. priorErrors is the number of review-error and
// review-pairing-degraded events already recorded for the current result_rev:
//   - 0 errors → floor = impl.ActualPower + 1 (standard R4 pairing)
//   - 1 error  → floor = impl.ActualPower + 2 (one ladder step up)
//   - 2+ errors → top-of-ladder profile (SelectStrongestProfile)
//
// A "reviewer-escalated" event is emitted via r.BeadEvents on each bump.
func (r *DefaultBeadReviewer) reviewerDispatchProfile(ctx context.Context, impl ImplementerRouting, priorErrors int) reviewerDispatchProfile {
	floor := 0
	if impl.ActualPower > 0 {
		floor = impl.ActualPower + 1
		if priorErrors == 1 {
			floor = impl.ActualPower + 2
		} else if priorErrors >= 2 {
			floor = impl.ActualPower + 2 // snap path uses SelectStrongestProfile; Runner path uses this floor
		}
	}
	escalated := priorErrors > 0
	topOfLadder := priorErrors >= 2

	emitEscalatedEvent := func(minPower int) {
		if !escalated || r.BeadEvents == nil {
			return
		}
		beadID := impl.Correlation["bead_id"]
		if beadID == "" {
			return
		}
		resultRev := impl.Correlation["result_rev"]
		_ = r.BeadEvents.AppendEvent(beadID, bead.BeadEvent{
			Kind:      ReviewerEscalatedEventKind,
			Summary:   fmt.Sprintf("reviewer escalated to min_power=%d after %d prior error(s)", minPower, priorErrors),
			Body:      reviewerEscalatedEventBody(minPower, priorErrors, resultRev),
			Source:    "ddx agent execute-loop",
			CreatedAt: time.Now().UTC(),
		})
	}

	if r.Runner != nil {
		emitEscalatedEvent(floor)
		return reviewerDispatchProfile{MinPower: floor}
	}
	selectedSvc := r.Service
	if selectedSvc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(r.ProjectRoot)
		if err != nil {
			emitEscalatedEvent(floor)
			return reviewerDispatchProfile{MinPower: floor}
		}
		selectedSvc = built
	}
	snap, err := LoadProfileSnapshot(ctx, selectedSvc)
	if err != nil {
		emitEscalatedEvent(floor)
		return reviewerDispatchProfile{MinPower: floor}
	}
	name := ""
	if topOfLadder {
		name = SelectStrongestProfile(snap)
	} else if floor > 0 {
		name = SelectStrongestProfileAbove(snap, floor)
	} else {
		name = selectSmartReviewerProfile(snap)
	}
	if name == "" {
		emitEscalatedEvent(floor)
		return reviewerDispatchProfile{MinPower: floor}
	}
	for _, profile := range snap.Profiles {
		if profile.Name == name {
			emitEscalatedEvent(profile.MinPower)
			return reviewerDispatchProfile{Name: name, MinPower: profile.MinPower}
		}
	}
	emitEscalatedEvent(floor)
	return reviewerDispatchProfile{Name: name, MinPower: floor}
}

