// TestReviewerEscalation_OnSecondTransportError asserts that when one prior
// review-error event is recorded for the current result_rev, the reviewer
// MinPower is bumped by one ladder step (impl.ActualPower+2 instead of +1).
func TestReviewerEscalation_OnSecondTransportError(t *testing.T) {
	projectRoot, head, store := reviewPairingTestSetup(t)
	events := &stubBeadEventAppender{}

	// Pre-populate: 1 review-error event for this result_rev.
	require.NoError(t, store.AppendEvent("ddx-pairing", bead.BeadEvent{
		Kind:      "review-error",
		Summary:   "transport",
		Body:      "failure_class=transport\nattempt_count=1\nresult_rev=" + head,
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}))

	runner := &reviewRunnerStub{result: &Result{
		Harness:     "claude",
		Provider:    "anthropic",
		Model:       "claude-opus-4-7",
		ActualPower: 95,
		Output:      reviewerOutputApprove,
	}}
	reviewer := &DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   store,
		BeadEvents:  events,
		EventStore:  store,
		Runner:      runner,
	}

	_, err := reviewer.ReviewBead(context.Background(), "ddx-pairing", head, ImplementerRouting{
		Harness:     "codex",
		Provider:    "openai",
		Model:       "gpt-5",
		ActualPower: 50,
		Correlation: map[string]string{
			"bead_id":    "ddx-pairing",
			"result_rev": head,
		},
	})
	require.NoError(t, err)

	// MinPowerOverride must be bumped to impl.ActualPower+2 = 52.
	assert.Equal(t, 52, runner.lastOpts.MinPower,
		"second transport error must bump reviewer MinPower to impl.ActualPower+2")

	// A reviewer-escalated event must be emitted.
	var escalated *bead.BeadEvent
	for i := range events.events {
		if events.events[i].Event.Kind == ReviewerEscalatedEventKind {
			ev := events.events[i].Event
			escalated = &ev
			break
		}
	}
	require.NotNil(t, escalated, "reviewer-escalated event must be emitted on MinPower bump")
	assert.Contains(t, escalated.Body, "new_min_power=52")
	assert.Contains(t, escalated.Body, "review_error_count=1")
}

