		Kind:      "review-error",
		Summary:   "transport",
		Body:      "failure_class=transport\nattempt_count=1\nresult_rev=" + head,
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}))

	reviewer := &DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   store,
		BeadEvents:  events,
		EventStore:  store,
		Runner: &reviewRunnerStub{result: &Result{
			Harness:     "claude",
			Provider:    "anthropic",
			Model:       "claude-opus-4-7",
			ActualPower: 95,
			Output:      reviewerOutputApprove,
		}},
	}

	impl := ImplementerRouting{
		Harness:     "codex",
		Provider:    "openai",
		Model:       "gpt-5",
		ActualPower: 50,
		Correlation: map[string]string{
			"bead_id":    "ddx-pairing",
			"result_rev": head,
		},
	}

	// Verify countPriorEscalationTriggers sees the one review-error event.
	priorErrors := countPriorEscalationTriggers(store, "ddx-pairing", head)
	assert.Equal(t, 1, priorErrors, "one review-error event must yield priorErrors=1")

	// Verify reviewerDispatchProfile bumps MinPower to impl.ActualPower+2.
	profile := reviewer.reviewerDispatchProfile(context.Background(), impl, priorErrors)
	assert.Equal(t, 52, profile.MinPower,
		"second transport error must bump reviewer MinPower to impl.ActualPower+2")

	// A reviewer-escalated event must be emitted via BeadEvents.
	var escalated *bead.BeadEvent
	for i := range events.events {
		if events.events[i].Event.Kind == ReviewerEscalatedEventKind {
			ev := events.events[i].Event
			escalated = &ev
			break
		}
	}
	require.NotNil(t, escalated, "reviewer-escalated event must be emitted on MinPower bump")
	assert.Contains(t, escalated.Body, "new_min_power=52")
	assert.Contains(t, escalated.Body, "review_error_count=1")

	// Full ReviewBead path must emit the escalated event (end-to-end).
	events.events = events.events[:0]
	_, err := reviewer.ReviewBead(context.Background(), "ddx-pairing", head, impl)
	require.NoError(t, err)
	foundEscalated := false
	for _, ev := range events.events {
		if ev.Event.Kind == ReviewerEscalatedEventKind {
			foundEscalated = true
			assert.Contains(t, ev.Event.Body, "new_min_power=52")
			break
		}
	}
	assert.True(t, foundEscalated, "end-to-end ReviewBead must emit reviewer-escalated event")
}

// TestReviewerEscalation_OnThirdError_TopOfLadder asserts that after two prior
// review-error events for the same result_rev, reviewerDispatchProfile selects
// the top-of-ladder profile (SelectStrongestProfile) rather than a floor-
// filtered profile, and emits a reviewer-escalated event.
func TestReviewerEscalation_OnThirdError_TopOfLadder(t *testing.T) {
	resetProfileSnapshotCacheForTest(t)

	svc := &profileSnapshotServiceStub{
		profiles: []agentlib.PolicyInfo{
			{Name: "cheap", MinPower: 10, MaxPower: 30},
			{Name: "standard", MinPower: 50, MaxPower: 70},
			{Name: "strong", MinPower: 90, MaxPower: 100},
		},
		models: []agentlib.ModelInfo{
			{ID: "cheap-model", Power: 20, Available: true, AutoRoutable: true},
			{ID: "standard-model", Power: 60, Available: true, AutoRoutable: true},
			{ID: "strong-model", Power: 95, Available: true, AutoRoutable: true},
		},
	}
	events := &stubBeadEventAppender{}

	reviewer := &DefaultBeadReviewer{
		Service:    svc,
		BeadEvents: events,
	}

	impl := ImplementerRouting{
		ActualPower: 50,
		Correlation: map[string]string{
			"bead_id":    "ddx-top-ladder",
			"result_rev": "abc123",
		},
	}

	// Two prior errors → top-of-ladder.
	profile := reviewer.reviewerDispatchProfile(context.Background(), impl, 2)

	assert.Equal(t, "strong", profile.Name,
		"two prior errors must select the top-of-ladder profile")
	assert.Equal(t, 90, profile.MinPower,
		"two prior errors must use top-of-ladder profile's MinPower")

	// Escalation event must be emitted.
	var escalated *bead.BeadEvent
	for i := range events.events {
		if events.events[i].Event.Kind == ReviewerEscalatedEventKind {
			ev := events.events[i].Event
			escalated = &ev
			break
		}
	}
	require.NotNil(t, escalated, "reviewer-escalated event must be emitted for top-of-ladder escalation")
	assert.Contains(t, escalated.Body, "new_min_power=90")
	assert.Contains(t, escalated.Body, "review_error_count=2")
}

